onClick:
{{
  (() => {
    const selectedIds = tblSalaryPreview.selectedRows.map(sel => sel.id);

    const updatedBatch = (appsmith.store.salaryBatch || []).map(r => {
      if (selectedIds.includes(r.id)) {
        return { 
          ...r, 
          payment_mode: selBulkMode.selectedOptionValue,
          from_account_id: selBulkAccount.selectedOptionValue,
          bank_statement_entry_id: selBulkAccountRefNo.selectedOptionValue
        };
      }
      return r;
    });

    return storeValue('salaryBatch', updatedBatch);
  })()
}}
